// Generated from world-atlas countries-50m via d3-geo Mercator projection.
// Regenerate rather than editing by hand.

export const MAP_VIEWBOX = { width: 400, height: 600 };

export type MapProjection = { k: number; tx: number; ty: number };

export type MapGeometry = {
  paths: { name: string; d: string }[];
  projection: MapProjection;
};

/** Project a latitude/longitude onto the map's SVG coordinate space. */
export function projectToMap(projection: MapProjection, lat: number, lng: number) {
  const lambda = (lng * Math.PI) / 180;
  const phi = (lat * Math.PI) / 180;
  return {
    x: projection.tx + projection.k * lambda,
    y: projection.ty - projection.k * Math.log(Math.tan(Math.PI / 4 + phi / 2)),
  };
}

